class Solution:
    def mergeSort(self, head: ListNode) -> ListNode:
        if head is None or head.next is None:
            return head
        first = head
        while first.next and first.next.next:
            first = first.next
        second = first.next
        first.next = None
        first, second = self.divide(first), self.divide(second)
        return self.merge(first, second)

    def divide(self, head):
        if head is None:
            return None
        if head.next is None:
            return head
        slow, fast = head, head.next
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
        second = slow.next
        slow.next = None
        return head, second

    def merge(self, head1, head2):
        dummy = ListNode(0)
        cur = dummy
        while head1 and head2:
            if head1.val < head2.val:
                cur.next = head1
                head1 = head1.next
            else:
                cur.next = head2
                head2 = head2.next
            cur = cur.next
        cur.next = head1 if head1 else head2
        return dummy.next

